def import_string(dotted_path):
	try:
		module_path, class_name = dotted_path.rsplit('.', 1)
	except ValueError:
		msg = "%s doesn't look like a module path" % dotted_path
		six.reraise(ImportError, ImportError(msg), sys.exc_info()[2])
	module = import_module(module_path)
	try:
		return getattr(module, class_name)
	except AttributeError:
		msg = 'Module "%s" does not define a "%s" attribute/class' % (
			module_path, class_name)
		six.reraise(ImportError, ImportError(msg), sys.exc_info()[2])

def build_test(label):
	parts = label.split('.')
	if len(parts) < 2 or len(parts) > 3:
		raise ValueError("Test label '%s' should be of the form app.TestCase "
						 "or app.TestCase.test_method" % label)
	app_config = apps.get_app_config(parts[0])
	models_module = app_config.models_module
	tests_module = get_tests(app_config)
	test_modules = []
	if models_module:
		test_modules.append(models_module)
	if tests_module:
		test_modules.append(tests_module)
	TestClass = None
	for module in test_modules:
		TestClass = getattr(module, parts[1], None)
		if TestClass is not None:
			break
	try:
		if issubclass(TestClass, (unittest.TestCase, real_unittest.TestCase)):
			if len(parts) == 2:  
				try:
					return unittest.TestLoader().loadTestsFromTestCase(
						TestClass)
				except TypeError:
					raise ValueError(
						"Test label '%s' does not refer to a test class"
						% label)
			else:  
				return TestClass(parts[2])
	except TypeError:
		pass
	tests = []
	for module in test_modules:
		try:
			doctests = make_doctest(module)
			for test in doctests:
				if test._dt_test.name in (
						'%s.%s' % (module.__name__, '.'.join(parts[1:])),
						'%s.__test__.%s' % (
							module.__name__, '.'.join(parts[1:]))):
					tests.append(test)
		except ValueError:
			pass
	if not tests:
		raise ValueError("Test label '%s' does not refer to a test" % label)
	return unittest.TestSuite(tests)

def register_option(key, defval, doc='', validator=None, cb=None):
	import tokenize
	import keyword
	key = key.lower()
	if key in _registered_options:
		raise OptionError("Option '%s' has already been registered" % key)
	if key in _reserved_keys:
		raise OptionError("Option '%s' is a reserved key" % key)
	if validator:
		validator(defval)
	path = key.split('.')
	for k in path:
		if not bool(re.match('^' + tokenize.Name + '$', k)):
			raise ValueError("%s is not a valid identifier" % k)
		if keyword.iskeyword(k):
			raise ValueError("%s is a python keyword" % k)
	cursor = _global_config
	for i, p in enumerate(path[:-1]):
		if not isinstance(cursor, dict):
			raise OptionError("Path prefix to option '%s' is already an option"
							  % '.'.join(path[:i]))
		if p not in cursor:
			cursor[p] = {}
		cursor = cursor[p]
	if not isinstance(cursor, dict):
		raise OptionError("Path prefix to option '%s' is already an option"
						  % '.'.join(path[:-1]))
	cursor[path[-1]] = defval  
	_registered_options[key] = RegisteredOption(key=key, defval=defval,
												doc=doc, validator=validator,
												cb=cb)

